## 3️⃣ HARD MOVE #3 – Add a “Fridge‑Signal” Layer to the Map (≈ 4 min)

We’ll create a **new marker** that uses the `fridgePulse` animation as its visual cue. It will also store the raw waveform data so you can replay it later.

```js
// -------------------------------------------------
// 3️⃣ Add a Fridge‑Signal marker (uses fridgePulse animation)
// -------------------------------------------------
function addFridgeSignalMarker() {
  const { lat, lng } = map.getCenter();   // wherever you are now
  const marker = L.marker([lat, lng], {
    className: 'marker-fridge'            // custom CSS class
  }).addTo(map);

  // Popup with waveform playback + description
  const waveJSON = localStorage.getItem('fridgeWaveJSON');
  const popupHTML = `
    <strong>Fridge Signal</strong><br>
    <em>19‑second sine wave captured from the fridge.</em><br>
    ${waveJSON ? `<button id="playWave">▶️ Play Waveform</button>` : ''}
    <br><small>${new Date().toLocaleTimeString()}</small>
  `;
  marker.bindPopup(popupHTML).openPopup();

  // Playback button – reconstruct the audio from the saved samples
  marker.on('popupopen', () => {
    const btn = document.getElementById('playWave');
    if (!btn) return;
    btn.onclick = () => {
      const samples = JSON.parse(waveJSON);
      const audioCtx = new (window.AudioContext || window.webkitAudioContext)();
      const buffer = audioCtx.createBuffer(1, samples.length, audioCtx.sampleRate);
      buffer.copyToChannel(new Float32Array(samples), 0);
      const source = audioCtx.createBufferSource();
      source.buffer = buffer;
      source.connect(audioCtx.destination);
      source.start();
    };
  });

  // Store for later (e.g., drawing a line)
  window.markers = window.markers || [];
  window.markers.push(marker);
}
addFridgeSignalMarker();
```

