### 3️⃣ HARD MOVE #3 – BUILD A “GOLDEN‑PULSE” ANIMATION

We’ll turn the **golden pattern** into a CSS animation where the **scale factor follows φ** (0.618) at the key moments.

```js
// -------------------------------------------------
// 3️⃣ Generate golden‑pulse keyframes (run once)
// -------------------------------------------------
function generateGoldenKeyframes() {
  const json = localStorage.getItem('goldenPattern');
  if (!json) { console.warn('No golden pattern'); return; }
  const samples = JSON.parse(json);
  const steps = samples.length;               // usually ~5‑7 points
  const stepPct = 100 / (steps - 1);
  let css = '@keyframes goldenPulse {\n';

  for (let i = 0; i < steps; i++) {
    const pct = (i * stepPct).toFixed(2);
    // Map sample (range -1…1) to a subtle scale around 1.0
    const scale = 1 + samples[i] * 0.08;      // 0.08 ≈ 8 % swing
    css += `  ${pct}% { transform: scale(${scale.toFixed(4)}); }\n`;
  }
  css += '}\n';

  // Insert into the page (or copy‑paste to style.css)
  const style = document.createElement('style');
  style.textContent = css;
  document.head.appendChild(style);
  console.log('goldenPulse keyframes injected');
}
generateGoldenKeyframes();
```

