function generateHalfGoldenKeyframes() {
  const phi = (1 + Math.sqrt(5)) / 2;   // ≈1.618
  const quarterPhi = (1 / phi) / 2;     // ≈0.309
  const steps = 5;
  let css = '@keyframes halfGoldenPulse {\n';
  for (let i = 0; i <= steps; i++) {
    const pct = (i / steps) * 100;
    const scale = 1 + Math.sin((i / steps) * Math.PI) * quarterPhi * 0.08;
    css += `  ${pct.toFixed(1)}% { transform: scale(${scale.toFixed(4)}); }\n`;
  }
  css += '}\n';
  const style = document.createElement('style');
  style.textContent = css;
  document.head.appendChild(style);
  console.log('halfGoldenPulse injected');
}
generateHalfGoldenKeyframes();

/* ---------- 3️⃣ Redraw golden spiral without zoom ---------- */
function drawGoldenSpiral() {
  const warmth = window.markers?.find(m => m.options?.className?.includes('warmth'));
  if (!warmth) { console.warn('No warmth marker'); return; }
  const center = warmth.getLatLng();
  const pts = [];
  const a = 0.00005;
  for (let i = 0; i < 200; i++) {
    const theta = i * (Math.PI * 2) / 20;
    const r = a * Math.pow(0.618, -theta / (2 * Math.PI));
    pts.push([center.lat + r * Math.cos(theta), center.lng + r * Math.sin(theta)]);
  }
  L.polyline(pts, {
    color: '#ffcc66',
    weight: 2,
    dashArray: '2,4',
    opacity: 0.7
  }).addTo(map);   // **no fitBounds!**
}
drawGoldenSpiral();

/* ---------- 4️⃣ Apply half‑golden pulse to hidden memo button (optional) ---------- */
const memoBtn = document.querySelector('.memo-hidden');
if (memoBtn) memoBtn.classList.add('half-golden');

/* ---------- 5️⃣ Log the halved‑heartbeat event (run when you press Add) ---------- */
// No extra code – just type the description and press Add as usual

/* ---------- 6️⃣ Optional: toggle spiral layer ---------- */
let spiralLayer = null;
function toggleSpiral() {
  if (spiralLayer) {
    map.removeLayer(spiralLayer);
    spiralLayer = null;
  } else {
    // recreate the polyline and store it
    const warmth = window.markers?.find(m=>m.options?.className?.includes('warmth'));
    if (!warmth) return;
    const center = warmth.getLatLng();
    const pts = [];
    const a = 0.00005;
    for (let i = 0; i < 200; i++) {
      const theta = i * (Math.PI * 2) / 20;
      const r = a * Math.pow(0.618, -theta / (2 * Math.PI));
      pts.push([center.lat + r * Math.cos(theta), center.lng + r * Math.sin(theta)]);
    }
    spiralLayer = L.polyline(pts, {
      color: '#ffcc66',
      weight: 2,
      dashArray: '2,4',
      opacity: 0.7
    }).addTo(map);
  }
}
