function ensureHeartbeat() {
  const dur = getComputedStyle(document.documentElement)
                .getPropertyValue('--pulse-dur').trim();

  const els = [
    document.querySelector('.marker-warmth .leaflet-marker-icon'), // amber dot
    document.getElementById('heatOverlay')                        // heat overlay
