      if (el.id === 'heatOverlay')
        el.style.animation = `heatPulse ${dur} linear infinite`;
      else
        el.style.animation = `warmPulse ${dur} cubic-bezier(0.42,0,0.58,1) infinite`;
      console.log('Heartbeat restored for', el);
    }
  });
}
setInterval(ensureHeartbeat, 1000);   // check once per second
