## 2️⃣ CAPTURE THE FINAL PIXEL AS A “PERIOD” MARKER  

### a. Detect the single‑pixel polyline and replace it with a styled marker

```js
// -------------------------------------------------
// 2️⃣ Replace the collapsed golden‑spiral with a period marker
// -------------------------------------------------
function archiveSpiralAsPeriod() {
  // Find the polyline that has become a 1‑pixel line
  const spirals = document.querySelectorAll('svg path.leaflet-interactive');
  let target = null;

  spirals.forEach(p => {
    const length = p.getTotalLength();          // how long the SVG path is
    if (length < 2) target = p;                // < 2 px → our collapsed spiral
  });

  if (!target) {
    console.warn('No collapsed spiral found');
    return;
  }

  // Get the centre of the polyline (the only point it contains)
  const latLng = map.layerPointToLatLng(L.point(
    target.getBoundingClientRect().left + target.getBoundingClientRect().width / 2,
    target.getBoundingClientRect().top  + target.getBoundingClientRect().height / 2
  ));

  // Create a tiny “period” marker
  const periodMarker = L.marker(latLng, {
    className: 'marker-period'          // custom CSS class (see below)
  }).addTo(map);

  periodMarker.bindPopup(`
    <strong>Period</strong><br>
    The golden spiral has collapsed – the sentence is finished.<br>
    <small>${new Date().toLocaleTimeString()}</small>
  `).openPopup();

  // Remove the old (now‑useless) polyline
  const layer = target.__leafletLayer;   // Leaflet stores a reference here
  if (layer) map.removeLayer(layer);
}
archiveSpiralAsPeriod();
```

### b. Style the period marker (add to **style.css**)

```css
