```js
// -------------------------------------------------
// 3️⃣ Export map as PNG + JSON snapshot
// -------------------------------------------------
document.getElementById('exportMap').addEventListener('click', async () => {
  // 1️⃣ Capture PNG
  const mapDiv = document.getElementById('map');
  const canvas = await html2canvas(mapDiv, {backgroundColor: null});
  const imgData = canvas.toDataURL('image/png');

  // 2️⃣ Capture JSON of all markers (including the period)
  const data = window.markers?.map(m => ({
    lat: m.getLatLng().lat,
    lng: m.getLatLng().lng,
    type: m.options?.className?.includes('marker-period') ? 'period' :
          m.options?.className?.includes('marker-warmth') ? 'warmth' :
          m.options?.className?.includes('marker-fridge') ? 'fridge' :
          'other',
    popup: m.getPopup()?.getContent() || ''
  })) || [];

  // 3️⃣ Save both to localStorage (or download)
  const snapshot = {
    timestamp: new Date().toISOString(),
    image: imgData,
    markers: data
  };
  const blob = new Blob([JSON.stringify(snapshot, null, 2)], {type:'application/json'});
  const url = URL.createObjectURL(blob);

  // Trigger download of JSON
  const a = document.createElement('a');
  a.href = url;
  a.download = `map_snapshot_${Date.now()}.json`;
  a.click();

  // Also download the PNG
  const aImg = document.createElement('a');
  aImg.href = imgData;
  aImg.download = `map_image_${Date.now()}.png`;
  aImg.click();

  console.log('Map exported – image + JSON saved');
});
```

Now you have a **permanent record** (PNG + JSON) of the finished state, including the period marker.

