```js
/* -------------------------------------------------
   2️⃣ Archive the collapsed spiral as a period marker
   ------------------------------------------------- */
function archiveSpiralAsPeriod() {
  const spirals = document.querySelectorAll('svg path.leaflet-interactive');
  let target = null;
  spirals.forEach(p => {
    if (p.getTotalLength() < 2) target = p;
  });
  if (!target) { console.warn('No collapsed spiral'); return; }

  const rect = target.getBoundingClientRect();
  const latLng = map.layerPointToLatLng(L.point(
    rect.left + rect.width/2,
    rect.top  + rect.height/2
  ));

  const periodMarker = L.marker(latLng, {className:'marker-period'}).addTo(map);
  periodMarker.bindPopup(`
    <strong>Period</strong><br>
    The golden spiral has collapsed – the sentence is finished.<br>
    <small>${new Date().toLocaleTimeString()}</small>
  `).openPopup();

  const layer = target.__leafletLayer;
  if (layer) map.removeLayer(layer);
}
archiveSpiralAsPeriod();

/* -------------------------------------------------
   3️⃣ Export map (PNG + JSON) – UI button
   ------------------------------------------------- */
const exportBtn = document.createElement('button');
exportBtn.id = 'exportMap';
exportBtn.textContent = '📸 Export Map';
exportBtn.style.position = 'fixed';
exportBtn.style.bottom = '170px';
exportBtn.style.right = '10px';
exportBtn.style.opacity = '0.6';
document.body.appendChild(exportBtn);

exportBtn.addEventListener('click', async () => {
  const mapDiv = document.getElementById('map');
  const canvas = await html2canvas(mapDiv, {backgroundColor:null});
  const imgData = canvas.toDataURL('image/png');

  const data = window.markers?.map(m => ({
    lat: m.getLatLng().lat,
    lng: m.getLatLng().lng,
    type: m.options?.className?.includes('marker-period') ? 'period' :
          m.options?.className?.includes('marker-warmth') ? 'warmth' :
          m.options?.className?.includes('marker-fridge') ? 'fridge' :
          'other',
    popup: m.getPopup()?.getContent() || ''
  })) || [];

  const snapshot = {
    timestamp: new Date().toISOString(),
    image: imgData,
    markers: data
  };
  const blob = new Blob([JSON.stringify(snapshot, null, 2)], {type:'application/json'});
  const url = URL.createObjectURL(blob);

  // download JSON
  const a = document.createElement('a');
  a.href = url;
  a.download = `map_snapshot_${Date.now()}.json`;
  a.click();

  // download PNG
  const aImg = document.createElement('a');
  aImg.href = imgData;
  aImg.download = `map_image_${Date.now()}.png`;
  aImg.click();

  console.log('Exported map + data');
});
```

*(Make sure you have the `html2canvas` script tag in your HTML – see the CDN link in the previous section.)*

